                    { value: "EUR", label: { tr: "Euro (EUR)", en: "Euro (EUR)" } },
                    { value: "GBP", label: { tr: "Sterlin (GBP)", en: "British Pound (GBP)" } },
                    { value: "TRY", label: { tr: "Lira (TRY)", en: "Lira (TRY)" } }
